const VIRTUE_ORDER = ['curiosity', 'investment', 'warmth', 'playfulness', 'directness', 'boldness', 'empathy', 'patience', 'vulnerability'];

const getZone = (value) => {
  if (value < -15) return 'negative';
  if (value > 15) return 'positive';
  return 'center';
};

const getZoneColor = (zone) => COLORS[zone];

// Virtue Slider Component
const VirtueSlider = ({ virtue, value, data, onChange, onEdit }) => {
  const zone = getZone(value);
  const zoneData = data.zones[zone];

  return (
    <div style={{ marginBottom: 16, padding: 12, background: COLORS.surface, borderRadius: 10, border: `1px solid ${data.color}33` }}>
      <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 8 }}>
        <div style={{ display: 'flex', alignItems: 'center', gap: 8 }}>
          <div style={{ width: 10, height: 10, borderRadius: '50%', background: data.color, boxShadow: `0 0 8px ${data.color}` }} />
          <span style={{ fontSize: 12, fontWeight: 600, color: data.color, textTransform: 'capitalize' }}>{virtue}</span>
        </div>
        <div style={{ display: 'flex', alignItems: 'center', gap: 8 }}>
          <span style={{ fontSize: 10, padding: '2px 8px', background: getZoneColor(zone), borderRadius: 10, color: '#fff' }}>
            {zoneData.label}
          </span>
          <span style={{ fontSize: 11, color: COLORS.textDim, fontFamily: 'monospace' }}>{value > 0 ? '+' : ''}{value}</span>
        </div>
      </div>

      {/* Slider */}
      <div style={{ position: 'relative', height: 24, marginBottom: 8 }}>
        <div style={{ position: 'absolute', top: 10, left: 0, right: 0, height: 4, background: COLORS.surfaceLight, borderRadius: 2 }}>
          {/* Zone indicators */}
          <div style={{ position: 'absolute', left: 0, width: '33%', height: '100%', background: `${COLORS.negative}44`, borderRadius: '2px 0 0 2px' }} />
          <div style={{ position: 'absolute', left: '33%', width: '34%', height: '100%', background: `${COLORS.center}44` }} />
          <div style={{ position: 'absolute', right: 0, width: '33%', height: '100%', background: `${COLORS.positive}44`, borderRadius: '0 2px 2px 0' }} />
        </div>
        <input
          type="range"
          min={-44}
          max={44}
          value={value}
          onChange={(e) => onChange(virtue, parseInt(e.target.value))}
          style={{ position: 'absolute', top: 0, left: 0, right: 0, width: '100%', height: 24, opacity: 0, cursor: 'pointer' }}
        />
        <div style={{
          position: 'absolute',
          top: 4,
          left: `${((value + 44) / 88) * 100}%`,
          transform: 'translateX(-50%)',
          width: 16,
          height: 16,
          background: data.color,
          borderRadius: '50%',
          boxShadow: `0 0 10px ${data.color}`,
          pointerEvents: 'none',
          transition: 'left 0.1s',
        }} />
      </div>

      {/* Zone labels */}
      <div style={{ display: 'flex', justifyContent: 'space-between', fontSize: 8, color: COLORS.textDim }}>
        <span>{data.zones.negative.label}</span>
        <span>{data.zones.center.label}</span>
        <span>{data.zones.positive.label}</span>
      </div>

      {/* Felt sense */}
      <div style={{ marginTop: 8, fontSize: 10, color: COLORS.textDim, fontStyle: 'italic' }}>
