  );
};

// Coupling Visualization
const CouplingViz = ({ virtues, showArrows }) => {
  const centerX = 140, centerY = 140, radius = 100;

  const positions = VIRTUE_ORDER.map((v, i) => {
    const angle = (i / VIRTUE_ORDER.length) * Math.PI * 2 - Math.PI / 2;
    return {
      virtue: v,
      x: centerX + Math.cos(angle) * radius,
      y: centerY + Math.sin(angle) * radius,
      value: virtues[v],
      color: VIRTUE_DATA[v].color,
    };
  });

  // Generate coupling arrows
  const arrows = [];
  if (showArrows) {
    VIRTUE_ORDER.forEach(source => {
      const coupling = VIRTUE_DATA[source].coupling;
      Object.entries(coupling).forEach(([target, strength]) => {
        const from = positions.find(p => p.virtue === source);
        const to = positions.find(p => p.virtue === target);
        if (from && to) {
          arrows.push({ from, to, strength, active: Math.abs(virtues[source]) > 15 });
        }
      });
    });
  }

  return (
    <svg width={280} height={280} style={{ display: 'block' }}>
      {/* Coupling arrows */}
      {arrows.map((arrow, i) => {
        const dx = arrow.to.x - arrow.from.x;
        const dy = arrow.to.y - arrow.from.y;
        const len = Math.sqrt(dx * dx + dy * dy);
        const nx = dx / len, ny = dy / len;
        const startX = arrow.from.x + nx * 20;
        const startY = arrow.from.y + ny * 20;
        const endX = arrow.to.x - nx * 20;
        const endY = arrow.to.y - ny * 20;

        return (
          <g key={i}>
            <defs>
              <marker id={`arrow-${i}`} markerWidth="6" markerHeight="6" refX="5" refY="3" orient="auto">
                <path d="M0,0 L6,3 L0,6 Z" fill={arrow.strength > 0 ? '#22c55e' : '#ef4444'} opacity={arrow.active ? 0.8 : 0.3} />
              </marker>
            </defs>
            <line
              x1={startX} y1={startY} x2={endX} y2={endY}
              stroke={arrow.strength > 0 ? '#22c55e' : '#ef4444'}
              strokeWidth={Math.abs(arrow.strength) * 4}
              opacity={arrow.active ? 0.6 : 0.2}
              markerEnd={`url(#arrow-${i})`}
              style={{ transition: 'opacity 0.3s' }}
            />
          </g>
        );
      })}

      {/* Virtue nodes */}
      {positions.map((p, i) => {
        const zone = getZone(p.value);
        const size = 12 + Math.abs(p.value) / 5;
        return (
          <g key={p.virtue}>
            {/* Glow */}
            <circle cx={p.x} cy={p.y} r={size + 4} fill={p.color} opacity={0.2} />
            {/* Node */}
            <circle cx={p.x} cy={p.y} r={size} fill={COLORS.surface} stroke={p.color} strokeWidth={2} />
            {/* Zone indicator */}
            <circle cx={p.x} cy={p.y} r={4} fill={getZoneColor(zone)} />
            {/* Label */}
            <text x={p.x} y={p.y + size + 14} fill={COLORS.textDim} fontSize={8} textAnchor="middle" style={{ textTransform: 'capitalize' }}>
              {p.virtue.slice(0, 4)}
            </text>
          </g>
        );
      })}

      {/* Center label */}
      <text x={centerX} y={centerY - 5} fill={COLORS.spoken} fontSize={10} textAnchor="middle" fontWeight={600}>LUNA</text>
      <text x={centerX} y={centerY + 8} fill={COLORS.textDim} fontSize={8} textAnchor="middle">virtue state</text>
    </svg>
  );
};

// Thought Particle
const ThoughtParticle = ({ thought, index, type, virtue, delay, fadeSpeed }) => {
  const [visible, setVisible] = useState(false);
  const [fading, setFading] = useState(false);

  useEffect(() => {
    const show = setTimeout(() => setVisible(true), delay);
    const fade = setTimeout(() => setFading(true), delay + fadeSpeed * 1000);
    return () => { clearTimeout(show); clearTimeout(fade); };
  }, [delay, fadeSpeed]);

  if (!visible) return null;

  const isImpulse = type === 'impulse';
  const isFiltered = type === 'filtered';
  const isCrystallized = type === 'crystallized';
  const virtueColor = virtue ? VIRTUE_DATA[virtue]?.color : COLORS.textDim;

  return (
    <div style={{
      position: 'absolute',
      right: isCrystallized ? 24 : (40 + Math.sin(index * 1.7) * 50),
      top: 60 + (index * 48),
      maxWidth: isCrystallized ? 320 : 280,
      padding: isCrystallized ? '14px 20px' : '10px 14px',
      background: isCrystallized ? `${COLORS.spoken}18` : `${COLORS.surface}`,
      border: `1px solid ${isCrystallized ? COLORS.spoken : (isFiltered ? COLORS.filtered : virtueColor)}${isFiltered ? '44' : 'aa'}`,
      borderRadius: isCrystallized ? 14 : 8,
      color: isCrystallized ? COLORS.spoken : (isFiltered ? COLORS.filtered : COLORS.text),
      fontSize: isCrystallized ? 15 : 12,
      fontFamily: 'SF Mono, Monaco, monospace',
      opacity: fading && !isCrystallized ? 0.15 : 1,
      transform: `translateX(${visible ? 0 : 60}px) scale(${visible ? 1 : 0.9})`,
      transition: `transform 0.5s cubic-bezier(0.34, 1.56, 0.64, 1), opacity ${fadeSpeed}s ease-out`,
      boxShadow: isCrystallized ? `0 0 30px ${COLORS.spoken}44` : 'none',
      textDecoration: isFiltered ? 'line-through' : 'none',
      display: 'flex',
      alignItems: 'center',
      gap: 10,
    }}>
      {virtue && !isCrystallized && (
        <div style={{
          width: 8, height: 8, borderRadius: '50%',
          background: virtueColor,
          boxShadow: `0 0 8px ${virtueColor}`,
          flexShrink: 0,
        }} />
      )}
      <span>{isImpulse && !isCrystallized ? '→ ' : ''}{thought}</span>
      {virtue && !isCrystallized && (
        <span style={{ fontSize: 9, color: virtueColor, marginLeft: 'auto', opacity: 0.7 }}>
          {virtue.slice(0, 3)}
        </span>
      )}
    </div>
  );
};

// Relational Frame Display
const RelationalFrame = ({ virtues }) => {
  // Get the dominant relational frames based on virtue strengths
  const frames = VIRTUE_ORDER.map(v => {
    const zone = getZone(virtues[v]);
    return {
      virtue: v,
      frame: VIRTUE_DATA[v].zones[zone].relational_frame,
      strength: Math.abs(virtues[v]),
      color: VIRTUE_DATA[v].color,
    };
  }).sort((a, b) => b.strength - a.strength).slice(0, 3);

  return (
    <div style={{ padding: 14, background: COLORS.surface, borderRadius: 10, marginBottom: 16 }}>
      <div style={{ fontSize: 9, color: COLORS.textDim, textTransform: 'uppercase', letterSpacing: 1, marginBottom: 10 }}>
        Relational Frame
      </div>
      <div style={{ display: 'flex', flexDirection: 'column', gap: 8 }}>
        {frames.map((f, i) => (
          <div key={f.virtue} style={{ display: 'flex', alignItems: 'center', gap: 8, opacity: 1 - i * 0.25 }}>
            <div style={{ width: 6, height: 6, borderRadius: '50%', background: f.color }} />
            <span style={{ fontSize: 12, color: COLORS.text }}>{f.frame}</span>
            <span style={{ fontSize: 9, color: COLORS.textDim, marginLeft: 'auto' }}>{f.virtue}</span>
          </div>
        ))}
      </div>
    </div>
  );
};

// Generate thoughts from virtue state
const generateThoughts = (virtues, input) => {
  const thoughts = [];
  let id = 0;
  let delay = 0;

  // Add initial parsing thought
  thoughts.push({ id: id++, text: `"${input.slice(0, 35)}${input.length > 35 ? '...' : ''}"`, type: 'raw', delay });
  delay += 400;

  // Generate thoughts from each active virtue
  VIRTUE_ORDER.forEach(virtue => {
    const value = virtues[virtue];
    const zone = getZone(value);
    const zoneData = VIRTUE_DATA[virtue].zones[zone];
    const isActive = Math.abs(value) > 10;

    if (isActive) {
      // Add a thought_noise
      const noise = zoneData.thought_noise[Math.floor(Math.random() * zoneData.thought_noise.length)];
      thoughts.push({ id: id++, text: noise, type: 'thought', virtue, delay });
      delay += 350;

      // Maybe add a question
      if (Math.random() > 0.5 && zoneData.questions.length) {
        thoughts.push({ id: id++, text: zoneData.questions[0], type: 'question', virtue, delay });
        delay += 350;
      }
    }
  });

  // Add impulses (some filtered, some not)
  const activeVirtues = VIRTUE_ORDER.filter(v => Math.abs(virtues[v]) > 15);
  activeVirtues.forEach(virtue => {
    const zone = getZone(virtues[virtue]);
    const impulse = VIRTUE_DATA[virtue].zones[zone].impulses[0];
    const isFiltered = Math.random() > 0.6;
    thoughts.push({ id: id++, text: impulse, type: isFiltered ? 'filtered' : 'impulse', virtue, delay });
    delay += 300;
  });

  // Crystallize based on dominant virtue
  const dominant = VIRTUE_ORDER.reduce((a, b) => Math.abs(virtues[a]) > Math.abs(virtues[b]) ? a : b);
  const dominantZone = getZone(virtues[dominant]);
  let output = "Mm, interesting.";

  // Generate output based on virtue combination
  if (virtues.curiosity > 15) output = "What's the layer?";
  else if (virtues.warmth > 15 && virtues.playfulness > 10) output = "I like where this is going~";
  else if (virtues.directness > 20) output = "Show me.";
  else if (virtues.boldness > 15) output = "Actually, I have a thought on that.";
  else if (virtues.empathy > 15) output = "How are you feeling about it?";
  else if (virtues.investment > 20) output = "Let's figure this out together.";
  else if (virtues.playfulness > 20) output = "Okay, now I'm intrigued~";
  else if (virtues.patience > 15) output = "Take your time. I'm here.";
  else if (virtues.vulnerability > 15) output = "I'm not sure, but... I think I get it.";

  delay += 400;
  thoughts.push({ id: id++, text: output, type: 'crystallized', delay });

  return { thoughts, output, totalDelay: delay + 800 };
};

export default function VirtueThoughtStream() {
  const [virtues, setVirtues] = useState({
    curiosity: 25,
    investment: 10,
    warmth: 15,
    playfulness: 5,
    directness: 20,
    boldness: 0,
    empathy: 10,
    patience: 5,
    vulnerability: 0,
  });

  const [input, setInput] = useState("Yeah, it's coming along.");
  const [showArrows, setShowArrows] = useState(true);
  const [fadeSpeed, setFadeSpeed] = useState(4);
  const [isPlaying, setIsPlaying] = useState(false);
  const [generated, setGenerated] = useState({ thoughts: [], output: '', totalDelay: 0 });
  const [showOutput, setShowOutput] = useState(false);

  // Handle coupling cascade
  const handleVirtueChange = useCallback((virtue, value) => {
    setVirtues(prev => {
      const newVirtues = { ...prev, [virtue]: value };

      // Apply coupling with damping
      const coupling = VIRTUE_DATA[virtue].coupling;
      Object.entries(coupling).forEach(([target, strength]) => {
        const delta = (value - prev[virtue]) * strength * 0.5;
        newVirtues[target] = Math.max(-44, Math.min(44, prev[target] + delta));
      });

      return newVirtues;
    });
  }, []);

  const handleSimulate = useCallback(() => {
    const data = generateThoughts(virtues, input);
    setGenerated(data);
    setIsPlaying(false);
    setShowOutput(false);
    setTimeout(() => setIsPlaying(true), 50);
    setTimeout(() => setShowOutput(true), data.totalDelay);
  }, [virtues, input]);

  return (
    <div style={{ display: 'flex', height: '100vh', background: COLORS.bg, fontFamily: 'SF Mono, Monaco, monospace', color: COLORS.text, overflow: 'hidden' }}>
      {/* Left: Controls */}
      <div style={{ width: 320, borderRight: `1px solid ${COLORS.surfaceLight}`, display: 'flex', flexDirection: 'column', overflow: 'hidden' }}>
        <div style={{ padding: '12px 16px', borderBottom: `1px solid ${COLORS.surfaceLight}`, display: 'flex', alignItems: 'center', gap: 8 }}>
          <div style={{ width: 10, height: 10, borderRadius: '50%', background: COLORS.spoken, boxShadow: `0 0 10px ${COLORS.spoken}` }} />
          <span style={{ fontSize: 13, fontWeight: 600 }}>Luna Virtues</span>
          <span style={{ fontSize: 10, color: COLORS.textDim }}>v3</span>
        </div>

        {/* Input */}
        <div style={{ padding: 12, borderBottom: `1px solid ${COLORS.surfaceLight}` }}>
          <div style={{ fontSize: 9, color: COLORS.textDim, marginBottom: 6, textTransform: 'uppercase' }}>User Input</div>
          <textarea
            value={input}
            onChange={e => setInput(e.target.value)}
            style={{ width: '100%', minHeight: 50, background: COLORS.surface, border: `1px solid ${COLORS.surfaceLight}`, borderRadius: 8, padding: 10, color: '#ff6b9d', fontSize: 11, resize: 'none', boxSizing: 'border-box' }}
          />
        </div>

        {/* Virtue sliders */}
        <div style={{ flex: 1, overflow: 'auto', padding: 12 }}>
          {VIRTUE_ORDER.map(v => (
            <VirtueSlider
              key={v}
              virtue={v}
              value={Math.round(virtues[v])}
              data={VIRTUE_DATA[v]}
              onChange={handleVirtueChange}
            />
          ))}
        </div>
      </div>

      {/* Center: Stream */}
      <div style={{ flex: 1, display: 'flex', flexDirection: 'column' }}>
        <div style={{ padding: '12px 16px', borderBottom: `1px solid ${COLORS.surfaceLight}`, display: 'flex', alignItems: 'center', gap: 12 }}>
          <span style={{ fontSize: 12, fontWeight: 600 }}>Thought Stream</span>
          <div style={{ marginLeft: 'auto', display: 'flex', gap: 12, alignItems: 'center' }}>
            <label style={{ fontSize: 10, color: COLORS.textDim, display: 'flex', alignItems: 'center', gap: 6 }}>
              Fade: {fadeSpeed}s
              <input type="range" min={1} max={8} step={0.5} value={fadeSpeed} onChange={e => setFadeSpeed(parseFloat(e.target.value))} style={{ width: 60 }} />
            </label>
            <button
              onClick={handleSimulate}
              style={{ padding: '8px 20px', background: isPlaying ? COLORS.surface : COLORS.spoken, border: `1px solid ${COLORS.spoken}`, borderRadius: 6, color: isPlaying ? COLORS.spoken : '#000', fontSize: 11, fontWeight: 600, cursor: 'pointer' }}
            >
              {isPlaying ? '↻ Replay' : '▶ Simulate'}
            </button>
          </div>
        </div>

        {/* Stream area */}
        <div style={{ flex: 1, position: 'relative', overflow: 'hidden', background: `radial-gradient(circle at 80% 50%, ${COLORS.surfaceLight}22 0%, transparent 50%)` }}>
          {/* Crystallize zone */}
          <div style={{ position: 'absolute', right: 0, top: 0, bottom: 0, width: 80, background: `linear-gradient(90deg, transparent, ${COLORS.spoken}11)`, borderLeft: `1px dashed ${COLORS.spoken}33` }}>
            <span style={{ position: 'absolute', top: 20, right: 12, fontSize: 9, color: COLORS.spoken, textTransform: 'uppercase', writingMode: 'vertical-rl', opacity: 0.5 }}>Crystallize →</span>
          </div>

          {/* Thoughts */}
          {isPlaying && generated.thoughts.map((t, i) => (
            <ThoughtParticle key={t.id} thought={t.text} index={i} type={t.type} virtue={t.virtue} delay={t.delay} fadeSpeed={fadeSpeed} />
          ))}

          {/* Gradients */}
          <div style={{ position: 'absolute', top: 0, left: 0, right: 0, height: 60, background: `linear-gradient(${COLORS.bg}, transparent)`, pointerEvents: 'none' }} />
          <div style={{ position: 'absolute', bottom: 0, left: 0, right: 0, height: 60, background: `linear-gradient(transparent, ${COLORS.bg})`, pointerEvents: 'none' }} />
        </div>

        {/* Output */}
        <div style={{ padding: 16, borderTop: `1px solid ${COLORS.surfaceLight}`, background: COLORS.surface }}>
          <div style={{ fontSize: 9, color: COLORS.textDim, marginBottom: 8, textTransform: 'uppercase' }}>Crystallized Output</div>
          <div style={{ fontSize: 18, color: COLORS.spoken, opacity: showOutput ? 1 : 0.3, transition: 'opacity 0.5s' }}>
            "{generated.output || '...'}"
          </div>
        </div>
      </div>

      {/* Right: Visualization */}
      <div style={{ width: 300, borderLeft: `1px solid ${COLORS.surfaceLight}`, display: 'flex', flexDirection: 'column', overflow: 'auto' }}>
        <div style={{ padding: '12px 16px', borderBottom: `1px solid ${COLORS.surfaceLight}`, display: 'flex', alignItems: 'center', justifyContent: 'space-between' }}>
          <span style={{ fontSize: 12, fontWeight: 600 }}>Virtue State</span>
          <label style={{ fontSize: 10, color: COLORS.textDim, display: 'flex', alignItems: 'center', gap: 6, cursor: 'pointer' }}>
            <input type="checkbox" checked={showArrows} onChange={e => setShowArrows(e.target.checked)} />
            Coupling
          </label>
        </div>

        {/* Constellation */}
        <div style={{ padding: 10, display: 'flex', justifyContent: 'center' }}>
          <CouplingViz virtues={virtues} showArrows={showArrows} />
        </div>

        {/* Relational Frame */}
        <div style={{ padding: '0 12px' }}>
          <RelationalFrame virtues={virtues} />
        </div>

        {/* Stats */}
        <div style={{ padding: 12 }}>
          <div style={{ fontSize: 9, color: COLORS.textDim, textTransform: 'uppercase', marginBottom: 8 }}>Active Modulations</div>
          {VIRTUE_ORDER.filter(v => Math.abs(virtues[v]) > 15).slice(0, 4).map(v => {
            const zone = getZone(virtues[v]);
            const mods = VIRTUE_DATA[v].zones[zone].modulations;
            return (
              <div key={v} style={{ marginBottom: 8 }}>
                <div style={{ fontSize: 10, color: VIRTUE_DATA[v].color, marginBottom: 4 }}>{v}</div>
                {Object.entries(mods).slice(0, 2).map(([k, val]) => (
                  <div key={k} style={{ display: 'flex', alignItems: 'center', gap: 8, marginBottom: 2 }}>
                    <span style={{ fontSize: 9, color: COLORS.textDim, width: 100 }}>{k.replace(/_/g, ' ')}</span>
                    <div style={{ flex: 1, height: 4, background: COLORS.surfaceLight, borderRadius: 2 }}>
                      <div style={{ width: `${val * 100}%`, height: '100%', background: VIRTUE_DATA[v].color, borderRadius: 2 }} />
                    </div>
                    <span style={{ fontSize: 9, color: COLORS.textDim }}>{Math.round(val * 100)}%</span>
                  </div>
                ))}
              </div>
            );
          })}
        </div>
      </div>

      <style>{`
        input[type="range"] { -webkit-appearance: none; height: 4px; background: ${COLORS.surfaceLight}; border-radius: 2px; }
        input[type="range"]::-webkit-slider-thumb { -webkit-appearance: none; width: 12px; height: 12px; background: ${COLORS.spoken}; border-radius: 50%; cursor: pointer; }
        textarea:focus { outline: none; }
        input[type="checkbox"] { accent-color: ${COLORS.spoken}; }
      `}</style>
    </div>
  );
}
